export default function MarginSignalField(){const [active,setActive]=useState(1);const reduced=useReducedMotion();return <section className="w-full max-w-md rounded-[22px] border border-[#ececee] bg-white p-5 shadow-sm"><p className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">margin signal</p><div className="relative mt-4 h-48 overflow-hidden rounded-2xl bg-[#f8f8f8]"><i aria-hidden className="absolute bottom-4 left-5 top-4 w-px bg-[#111]/15"/>{points.map(([name,left,top],index)=><button key={name} type="button" aria-pressed={active===index} aria-label={`Select ${name} signal`} onClick={()=>setActive(index)} className="absolute z-10 grid h-11 w-11 -translate-x-1/2 -translate-y-1/2 place-items-center rounded-full outline-offset-3 focus-visible:outline focus-visible:outline-3 focus-visible:outline-[#111]" style={{left,top}}><motion.i animate={{scale:active===index&&!reduced?1.35:1}} transition={{type:"spring",stiffness:300,damping:26}} className={active===index?"h-3 w-3 rounded-full bg-[#f97360]":"h-2.5 w-2.5 rounded-full bg-[#c9c9cd]"}/></button>)}</div><p aria-live="polite" className="mt-3 text-sm text-[#4a4a4f]">Active locator: <b className="text-[#111]">{points[active][0]}</b>.</p></section>}
